#include <stdio.h>
#include <ctype.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char buf[256];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(buf, sizeof(buf), stdin)) break;
        size_t len = strlen(buf);
        if (len && buf[len-1] == '\n') buf[--len] = '\0';
        char cleaned[256];
        int pos = 0;
        for (size_t i = 0; i < len; ++i) {
            if (buf[i] == ' ') continue;
            cleaned[pos++] = toupper((unsigned char)buf[i]);
        }
        cleaned[pos] = '\0';
        int isNumeric = 1;
        if (pos == 0) isNumeric = 0; // empty string is not numeric
        for (int i = 0; i < pos && isNumeric; ++i) {
            if (!isdigit((unsigned char)cleaned[i])) isNumeric = 0;
        }
        printf("%s\n", cleaned);
        printf(isNumeric ? "True\n" : "False\n");
    }
    return 0;
}

