    cin.tie(nullptr);
    int T;
    if(!(cin>>T)) return 0;
    string line;
    getline(cin, line); // consume endline after T
    for(int tc=0; tc<T; ++tc){
        getline(cin, line);
        string cleaned;
        for(char ch: line){
            if(ch==' ') continue;
            cleaned.push_back(toupper((unsigned char)ch));
        }
        bool numeric = !cleaned.empty();
        for(char ch: cleaned){
            if(!isdigit((unsigned char)ch)) { numeric = false; break; }
        }
        cout << cleaned << '\n' << (numeric?"True":"False") << '\n';
    }
    return 0;
}

