#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    lines = data[1:1+T]
    for line in lines:
        cleaned = ''.join(ch.upper() for ch in line if ch != ' ')
        numeric = cleaned.isdigit() and len(cleaned) > 0
        print(cleaned)
        print('True' if numeric else 'False')

if __name__ == "__main__":
    main()

